const cfg = $input.first().json;
return (cfg.keywords || '')
  .split(',')
  .map(k => k.trim())
  .filter(Boolean)
  .map(q => ({ json: { query: q } }));

const out = [];
const items = $input.all();
for (let i = 0; i < items.length; i++) {
  const body = items[i].json || {};
  const query = $('Split Keywords').all()[i]?.json?.query || '';
  for (const v of (body.items || [])) {
    if (v.id && v.id.videoId) {
      out.push({ json: {
        query,
        videoId: v.id.videoId,
        videoTitle: v.snippet?.title || '',
        channelTitle: v.snippet?.channelTitle || ''
      }});
    }
  }
}
return out;

const out = [];
const items = $input.all();
for (let i = 0; i < items.length; i++) {
  const body = items[i].json || {};
  const meta = $('Extract Videos').all()[i]?.json || {};
  for (const t of (body.items || [])) {
    const s = t.snippet?.topLevelComment?.snippet;
    if (!s) continue;
    out.push({ json: {
      query: meta.query || '',
      videoId: meta.videoId || '',
      videoTitle: meta.videoTitle || '',
      url: 'https://www.youtube.com/watch?v=' + (meta.videoId || '') + '&lc=' + (t.snippet.topLevelComment.id || ''),
      author: s.authorDisplayName || '',
      text: s.textDisplay || '',
      likeCount: s.likeCount || 0,
      publishedAt: s.publishedAt || '',
      replyCount: t.snippet.totalReplyCount || 0
    }});
  }
}
return out;

const cfg = $('Config').first().json;
const minLikes = Number(cfg.minLikes) || 0;
const rules = (cfg.ruleKeywords || '').split(',').map(s => s.trim().toLowerCase()).filter(Boolean);
const out = [];
for (const item of $input.all()) {
  const t = (item.json.text || '').toLowerCase();
  const hit = (item.json.likeCount >= minLikes) || rules.some(r => t.includes(r));
  if (hit) out.push(item);
}
return out;

const out = [];
const items = $input.all();
for (let i = 0; i < items.length; i++) {
  const resp = items[i].json || {};
  const base = $('Rule Pre-filter').all()[i]?.json || {};
  let verdict = { match: false, category: 'other', reason: 'parse_error' };
  try {
    const txt = resp.content?.[0]?.text;
    if (txt) {
      const m = txt.match(/\{[\s\S]*\}/);
      if (m) verdict = JSON.parse(m[0]);
    }
  } catch (e) {}
  out.push({ json: { ...base, aiMatch: !!verdict.match, category: verdict.category || 'other', reason: verdict.reason || '' } });
}
return out;
